func TestEnumOrder(t *testing.T) {
	t.Run("NewFromString_asc", func(t *testing.T) {
		t.Parallel()
		val, err := NewOrderFromString("asc")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, Order("asc"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_desc", func(t *testing.T) {
		t.Parallel()
		val, err := NewOrderFromString("desc")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, Order("desc"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_Invalid", func(t *testing.T) {
		_, err := NewOrderFromString("invalid_value_that_does_not_exist")
		assert.Error(t, err)
	})

	t.Run("Ptr", func(t *testing.T) {
		val, err := NewOrderFromString("asc")
		assert.NoError(t, err)
		ptr := val.Ptr()
		assert.NotNil(t, ptr)
		assert.Equal(t, val, *ptr)
	})
}

